import{_ as e,o as a,c as r,Q as t}from"./chunks/framework.3daba8ea.js";const l="/assets/image.4dc0e1db.png",x=JSON.parse('{"title":"externalTrafficPolicy","description":"","frontmatter":{},"headers":[],"relativePath":"doc/DevOps/Kubernetes/基础/Controller/service/externalTrafficPolicy.md","filePath":"packages/doc/src/DevOps/Kubernetes/基础/Controller/service/externalTrafficPolicy.md","lastUpdated":1704383113000}'),o={name:"doc/DevOps/Kubernetes/基础/Controller/service/externalTrafficPolicy.md"},c=t('<h1 id="externaltrafficpolicy" tabindex="-1">externalTrafficPolicy <a class="header-anchor" href="#externaltrafficpolicy" aria-label="Permalink to &quot;externalTrafficPolicy&quot;">​</a></h1><ul><li><a href="https://www.cnblogs.com/zhangmingcheng/p/17637712.html" target="_blank" rel="noreferrer">参考</a></li></ul><h2 id="什么是external-traffic-policy" tabindex="-1">什么是external-traffic-policy <a class="header-anchor" href="#什么是external-traffic-policy" aria-label="Permalink to &quot;什么是external-traffic-policy&quot;">​</a></h2><p>在k8s的Service对象（申明一条访问通道）中，有一个“externalTrafficPolicy”字段可以设置。有2个值可以设置：Cluster或者Local。</p><p>1）Cluster表示：流量可以转发到其他节点上的Pod。</p><p>2）Local表示：流量只发给本机的Pod。 <img src="'+l+'" alt="Alt text"></p><h2 id="这2种模式有什么区别" tabindex="-1">这2种模式有什么区别 <a class="header-anchor" href="#这2种模式有什么区别" aria-label="Permalink to &quot;这2种模式有什么区别&quot;">​</a></h2><p>存在这2种模式的原因就是，当前节点的Kube-proxy在转发报文的时候，会不会保留原始访问者的IP。</p><h3 id="选择cluster" tabindex="-1">选择Cluster <a class="header-anchor" href="#选择cluster" aria-label="Permalink to &quot;选择Cluster&quot;">​</a></h3><p>注：这个是默认模式，Kube-proxy不管容器实例在哪，公平转发。</p><p>Kube-proxy转发时会替换掉报文的源IP。即：容器收的报文，源IP地址，已经被替换为上一个转发节点的了。 原因是Kube-proxy在做转发的时候，会做一次SNAT，所以源IP变成了节点1的IP地址。SNAT确保回去的报文可以原路返回，不然回去的路径不一样，客户会认为非法报文的。（我发给张三的，怎么李四给我回应？丢弃！）</p><p>这种模式好处是负载均衡会比较好，因为无论容器实例怎么分布在多个节点上，它都会转发过去。当然，由于多了一次转发，性能会损失一丢丢。</p><h3 id="选择local" tabindex="-1">选择Local <a class="header-anchor" href="#选择local" aria-label="Permalink to &quot;选择Local&quot;">​</a></h3><p>这种情况下，只转发给本机的容器，绝不跨节点转发。</p><p>Kube-proxy转发时会保留源IP。即：容器收到的报文，看到源IP地址还是用户的。</p><p>缺点是负载均衡可能不是很好，因为一旦容器实例分布在多个节点上，它只转发给本机，不跨节点转发流量。当然，少了一次转发，性能会相对好一丢丢。</p><p>注：这种模式下的Service类型只能为外部流量，即：LoadBalancer 或者 NodePort 两种，否则会报错。</p><p>同时，由于本机不会跨节点转发报文，所以要想所有节点上的容器有负载均衡，就需要上一级的Loadbalancer来做了。</p><h2 id="两种模式该怎么选" tabindex="-1">两种模式该怎么选 <a class="header-anchor" href="#两种模式该怎么选" aria-label="Permalink to &quot;两种模式该怎么选&quot;">​</a></h2><p>如何选择取决于你的应用程序需求和性能考虑。通常来说，大多数应用程序可以使用默认的 Cluster 模式，因为它可以提供相对平均的负载均衡。</p><p>但在一些特定的场景中，比如对于具有特殊网络依赖的应用程序；对于特定部署在固定节点的应用程序（比如 Nginx Ingress Controller 通常以高可用形式部署在固定三个节点上面），Local 模式可能更适合，因为它可以减少跨节点的网络传输。</p><p>不过注意，选了这个就得考虑好怎么处理好负载均衡问题（ps：通常我们使用Pod间反亲和来达成），如果你是从外部LB接收流量的，那么使用：Local 模式 + Pod 反亲和，一般是足够的；另外，访问的时候确保当前节点调度此 Pod 了，否则访问歇菜。</p>',22),i=[c];function n(s,p,d,f,h,u){return a(),r("div",null,i)}const _=e(o,[["render",n]]);export{x as __pageData,_ as default};
